import React, { useState, useCallback, useEffect } from 'react';
import { 
  Upload, AlertCircle, CheckCircle, Clock, Heart, Activity, 
  FileText, ChevronDown, ChevronUp, BarChart3, Send, X, 
  Calendar, Filter, Menu, Home, Image, File, Trash2, Check
} from 'lucide-react';
import './App.css';

// Types
interface EcoResult {
  tem_estenose: boolean;
  gravidade: string;
  area_valvar: number | null;
  gradiente_medio: number | null;
  velocidade_maxima: number | null;
  prioridade: string;
  justificativa: string;
  indicacao_tavi: boolean;
  confianca: number;
}

interface LaudoProcessado {
  id: string;
  arquivo: string;
  formato: string;
  timestamp: string;
  analise: EcoResult;
  texto_original?: string;
  encaminhado: boolean;
  data_encaminhamento?: string;
}

interface FileUploadStatus {
  file: File;
  status: 'pending' | 'uploading' | 'success' | 'error';
  progress: number;
  result?: LaudoProcessado;
  error?: string;
}

interface Stats {
  total_laudos: number;
  indicacao_tavi: number;
  prioridade_alta: number;
  prioridade_media: number;
  prioridade_baixa: number;
  encaminhados: number;
  periodo: string;
  por_gravidade?: Record<string, number>;
}

type View = 'upload' | 'dashboard';
type Periodo = 'dia' | 'semana' | 'mes' | 'todos' | 'custom';

const API_URL = 'http://localhost:8000';

const FORMATOS_ACEITOS = '.pdf,.txt,.png,.jpg,.jpeg,.webp,.gif,.bmp';

function App() {
  // Navigation
  const [view, setView] = useState<View>('upload');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  // Upload state
  const [uploadFiles, setUploadFiles] = useState<FileUploadStatus[]>([]);
  const [dragActive, setDragActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // Results state
  const [laudos, setLaudos] = useState<LaudoProcessado[]>([]);
  const [expandedCard, setExpandedCard] = useState<string | null>(null);

  // Dashboard state
  const [stats, setStats] = useState<Stats | null>(null);
  const [periodo, setPeriodo] = useState<Periodo>('todos');
  const [customDateStart, setCustomDateStart] = useState('');
  const [customDateEnd, setCustomDateEnd] = useState('');

  // Load stats and laudos
  const loadData = useCallback(async () => {
    try {
      let url = `${API_URL}/estatisticas?periodo=${periodo}`;
      if (periodo === 'custom' && customDateStart && customDateEnd) {
        url = `${API_URL}/estatisticas?periodo=custom&data_inicio=${customDateStart}&data_fim=${customDateEnd}`;
      }
      const statsRes = await fetch(url);
      const statsData = await statsRes.json();
      setStats(statsData);

      let laudosUrl = `${API_URL}/laudos?periodo=${periodo}`;
      if (periodo === 'custom' && customDateStart && customDateEnd) {
        laudosUrl = `${API_URL}/laudos?periodo=custom&data_inicio=${customDateStart}&data_fim=${customDateEnd}`;
      }
      const laudosRes = await fetch(laudosUrl);
      const laudosData = await laudosRes.json();
      setLaudos(laudosData.laudos || []);
    } catch (error) {
      console.error('Erro ao carregar dados:', error);
    }
  }, [periodo, customDateStart, customDateEnd]);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // Drag and drop handlers
  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      addFiles(Array.from(e.dataTransfer.files));
    }
  }, []);

  const addFiles = (files: File[]) => {
    const newFiles: FileUploadStatus[] = files.map(file => ({
      file,
      status: 'pending',
      progress: 0
    }));
    setUploadFiles(prev => [...prev, ...newFiles]);
  };

  const removeFile = (index: number) => {
    setUploadFiles(prev => prev.filter((_, i) => i !== index));
  };

  const processFiles = async () => {
    if (uploadFiles.length === 0) return;

    setIsProcessing(true);
    const updatedFiles = [...uploadFiles];

    for (let i = 0; i < updatedFiles.length; i++) {
      if (updatedFiles[i].status !== 'pending') continue;

      updatedFiles[i].status = 'uploading';
      updatedFiles[i].progress = 30;
      setUploadFiles([...updatedFiles]);

      try {
        const formData = new FormData();
        formData.append('file', updatedFiles[i].file);

        updatedFiles[i].progress = 60;
        setUploadFiles([...updatedFiles]);

        const response = await fetch(`${API_URL}/analisar-arquivo`, {
          method: 'POST',
          body: formData
        });

        if (!response.ok) {
          const error = await response.json();
          throw new Error(error.detail || 'Erro no processamento');
        }

        const result = await response.json();
        updatedFiles[i].status = 'success';
        updatedFiles[i].progress = 100;
        updatedFiles[i].result = result;
        setLaudos(prev => [result, ...prev]);

      } catch (error) {
        updatedFiles[i].status = 'error';
        updatedFiles[i].error = error instanceof Error ? error.message : 'Erro desconhecido';
      }

      setUploadFiles([...updatedFiles]);
    }

    setIsProcessing(false);
    loadData();
  };

  const clearCompleted = () => {
    setUploadFiles(prev => prev.filter(f => f.status === 'pending' || f.status === 'uploading'));
  };

  const toggleEncaminhado = async (laudoId: string, encaminhado: boolean) => {
    try {
      await fetch(`${API_URL}/encaminhar`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ laudo_id: laudoId, encaminhado })
      });

      setLaudos(prev => prev.map(l => 
        l.id === laudoId ? { ...l, encaminhado, data_encaminhamento: encaminhado ? new Date().toISOString() : undefined } : l
      ));
      loadData();
    } catch (error) {
      console.error('Erro ao atualizar encaminhamento:', error);
    }
  };

  const getFileIcon = (formato: string) => {
    switch (formato) {
      case 'pdf': return <FileText className="w-4 h-4" />;
      case 'imagem': return <Image className="w-4 h-4" />;
      default: return <File className="w-4 h-4" />;
    }
  };

  const getPrioridadeColor = (prioridade: string) => {
    switch (prioridade) {
      case 'alta': return 'bg-red-500';
      case 'media': return 'bg-amber-500';
      case 'baixa': return 'bg-emerald-500';
      default: return 'bg-slate-500';
    }
  };

  const getPrioridadeBg = (prioridade: string) => {
    switch (prioridade) {
      case 'alta': return 'bg-red-50 border-red-200';
      case 'media': return 'bg-amber-50 border-amber-200';
      case 'baixa': return 'bg-emerald-50 border-emerald-200';
      default: return 'bg-slate-50 border-slate-200';
    }
  };

  return (
    <div className="min-h-screen bg-slate-100">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-4">
              <img src="/logo.png" alt="CardioScreen" className="h-10 w-auto" />
            </div>

            {/* Desktop Nav */}
            <nav className="hidden md:flex items-center gap-1">
              <button
                onClick={() => setView('upload')}
                className={`px-4 py-2 rounded-lg font-medium transition-colors flex items-center gap-2 ${
                  view === 'upload' 
                    ? 'bg-blue-100 text-blue-700' 
                    : 'text-slate-600 hover:bg-slate-100'
                }`}
              >
                <Upload className="w-4 h-4" />
                Upload
              </button>
              <button
                onClick={() => setView('dashboard')}
                className={`px-4 py-2 rounded-lg font-medium transition-colors flex items-center gap-2 ${
                  view === 'dashboard' 
                    ? 'bg-blue-100 text-blue-700' 
                    : 'text-slate-600 hover:bg-slate-100'
                }`}
              >
                <BarChart3 className="w-4 h-4" />
                Dashboard
              </button>
            </nav>

            {/* Mobile menu button */}
            <button 
              className="md:hidden p-2 rounded-lg hover:bg-slate-100"
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            >
              <Menu className="w-6 h-6 text-slate-600" />
            </button>
          </div>

          {/* Mobile Nav */}
          {mobileMenuOpen && (
            <div className="md:hidden py-3 border-t border-slate-200">
              <button
                onClick={() => { setView('upload'); setMobileMenuOpen(false); }}
                className={`w-full px-4 py-3 text-left font-medium flex items-center gap-3 ${
                  view === 'upload' ? 'bg-blue-50 text-blue-700' : 'text-slate-600'
                }`}
              >
                <Upload className="w-5 h-5" />
                Upload de Laudos
              </button>
              <button
                onClick={() => { setView('dashboard'); setMobileMenuOpen(false); }}
                className={`w-full px-4 py-3 text-left font-medium flex items-center gap-3 ${
                  view === 'dashboard' ? 'bg-blue-50 text-blue-700' : 'text-slate-600'
                }`}
              >
                <BarChart3 className="w-5 h-5" />
                Dashboard
              </button>
            </div>
          )}
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 py-6">
        {/* UPLOAD VIEW */}
        {view === 'upload' && (
          <div className="space-y-6">
            {/* Upload Area */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-4 sm:p-6 border-b border-slate-100">
                <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <Upload className="w-5 h-5 text-blue-600" />
                  Upload de Laudos
                </h2>
                <p className="text-sm text-slate-500 mt-1">
                  PDF, imagens (PNG, JPG), TXT • Múltiplos arquivos
                </p>
              </div>

              <div className="p-4 sm:p-6">
                <div 
                  onDragEnter={handleDrag}
                  onDragLeave={handleDrag}
                  onDragOver={handleDrag}
                  onDrop={handleDrop}
                  className={`border-2 border-dashed rounded-xl transition-all ${
                    dragActive 
                      ? 'border-blue-500 bg-blue-50' 
                      : 'border-slate-300 hover:border-blue-400'
                  }`}
                >
                  <input
                    type="file"
                    multiple
                    accept={FORMATOS_ACEITOS}
                    onChange={(e) => e.target.files && addFiles(Array.from(e.target.files))}
                    className="hidden"
                    id="file-upload"
                  />
                  <label htmlFor="file-upload" className="cursor-pointer block p-8 sm:p-12 text-center">
                    <div className={`inline-flex p-4 rounded-full mb-4 ${dragActive ? 'bg-blue-100' : 'bg-slate-100'}`}>
                      <Upload className={`w-8 h-8 ${dragActive ? 'text-blue-600' : 'text-slate-400'}`} />
                    </div>
                    <p className="text-lg font-medium text-slate-700">
                      {dragActive ? 'Solte os arquivos aqui' : 'Arraste arquivos ou clique para selecionar'}
                    </p>
                    <p className="text-sm text-slate-500 mt-1">Suporta PDF, imagens e texto</p>
                  </label>
                </div>

                {/* File List */}
                {uploadFiles.length > 0 && (
                  <div className="mt-6 space-y-3">
                    <div className="flex items-center justify-between">
                      <h3 className="font-medium text-slate-700">
                        {uploadFiles.length} arquivo{uploadFiles.length > 1 ? 's' : ''} selecionado{uploadFiles.length > 1 ? 's' : ''}
                      </h3>
                      <button 
                        onClick={clearCompleted}
                        className="text-sm text-slate-500 hover:text-slate-700"
                      >
                        Limpar concluídos
                      </button>
                    </div>

                    <div className="space-y-2 max-h-64 overflow-y-auto">
                      {uploadFiles.map((item, index) => (
                        <div 
                          key={index}
                          className={`flex items-center gap-3 p-3 rounded-lg border ${
                            item.status === 'success' ? 'bg-emerald-50 border-emerald-200' :
                            item.status === 'error' ? 'bg-red-50 border-red-200' :
                            item.status === 'uploading' ? 'bg-blue-50 border-blue-200' :
                            'bg-slate-50 border-slate-200'
                          }`}
                        >
                          <div className="flex-shrink-0">
                            {item.status === 'success' ? (
                              <CheckCircle className="w-5 h-5 text-emerald-500" />
                            ) : item.status === 'error' ? (
                              <AlertCircle className="w-5 h-5 text-red-500" />
                            ) : item.status === 'uploading' ? (
                              <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" />
                            ) : (
                              <FileText className="w-5 h-5 text-slate-400" />
                            )}
                          </div>

                          <div className="flex-1 min-w-0">
                            <p className="text-sm font-medium text-slate-700 truncate">{item.file.name}</p>
                            {item.status === 'uploading' && (
                              <div className="mt-1 h-1.5 bg-slate-200 rounded-full overflow-hidden">
                                <div 
                                  className="h-full bg-blue-500 transition-all duration-300"
                                  style={{ width: `${item.progress}%` }}
                                />
                              </div>
                            )}
                            {item.status === 'success' && item.result && (
                              <p className="text-xs text-emerald-600 mt-0.5">
                                Prioridade: {item.result.analise.prioridade.toUpperCase()}
                              </p>
                            )}
                            {item.status === 'error' && (
                              <p className="text-xs text-red-600 mt-0.5">{item.error}</p>
                            )}
                          </div>

                          {item.status === 'pending' && (
                            <button 
                              onClick={() => removeFile(index)}
                              className="p-1 hover:bg-slate-200 rounded"
                            >
                              <X className="w-4 h-4 text-slate-400" />
                            </button>
                          )}
                        </div>
                      ))}
                    </div>

                    <button
                      onClick={processFiles}
                      disabled={isProcessing || uploadFiles.every(f => f.status !== 'pending')}
                      className="w-full py-3 bg-blue-600 text-white font-medium rounded-xl hover:bg-blue-700 disabled:bg-slate-300 disabled:cursor-not-allowed transition-colors flex items-center justify-center gap-2"
                    >
                      {isProcessing ? (
                        <>
                          <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                          Processando...
                        </>
                      ) : (
                        <>
                          <Activity className="w-5 h-5" />
                          Analisar {uploadFiles.filter(f => f.status === 'pending').length} arquivo{uploadFiles.filter(f => f.status === 'pending').length > 1 ? 's' : ''}
                        </>
                      )}
                    </button>
                  </div>
                )}
              </div>
            </div>

            {/* Results Table */}
            {laudos.length > 0 && (
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <div className="p-4 sm:p-6 border-b border-slate-100">
                  <h2 className="text-lg font-bold text-slate-800">
                    Resultados ({laudos.length})
                  </h2>
                </div>

                {/* Mobile Cards */}
                <div className="md:hidden divide-y divide-slate-100">
                  {laudos.slice(0, 20).map((laudo) => (
                    <div key={laudo.id} className={`p-4 ${getPrioridadeBg(laudo.analise.prioridade)}`}>
                      <div className="flex items-start justify-between gap-3">
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            {getFileIcon(laudo.formato)}
                            <span className="font-medium text-slate-800 truncate">{laudo.arquivo}</span>
                          </div>
                          <div className="flex items-center gap-2 mt-2">
                            <span className={`px-2 py-0.5 rounded text-xs font-bold text-white ${getPrioridadeColor(laudo.analise.prioridade)}`}>
                              {laudo.analise.prioridade.toUpperCase()}
                            </span>
                            {laudo.analise.indicacao_tavi && (
                              <span className="px-2 py-0.5 rounded text-xs font-bold bg-red-600 text-white flex items-center gap-1">
                                <Heart className="w-3 h-3" /> TAVI
                              </span>
                            )}
                          </div>
                        </div>
                        <button
                          onClick={() => toggleEncaminhado(laudo.id, !laudo.encaminhado)}
                          className={`p-2 rounded-lg transition-colors ${
                            laudo.encaminhado 
                              ? 'bg-emerald-100 text-emerald-600' 
                              : 'bg-slate-100 text-slate-400 hover:bg-slate-200'
                          }`}
                        >
                          <Send className="w-5 h-5" />
                        </button>
                      </div>

                      <button 
                        onClick={() => setExpandedCard(expandedCard === laudo.id ? null : laudo.id)}
                        className="mt-3 text-sm text-blue-600 font-medium"
                      >
                        {expandedCard === laudo.id ? 'Ver menos' : 'Ver detalhes'}
                      </button>

                      {expandedCard === laudo.id && (
                        <div className="mt-3 pt-3 border-t border-slate-200 space-y-2 text-sm">
                          <p><span className="text-slate-500">Gravidade:</span> <span className="font-medium capitalize">{laudo.analise.gravidade}</span></p>
                          <p><span className="text-slate-500">Área:</span> <span className="font-medium">{laudo.analise.area_valvar || 'N/A'} cm²</span></p>
                          <p><span className="text-slate-500">Gradiente:</span> <span className="font-medium">{laudo.analise.gradiente_medio || 'N/A'} mmHg</span></p>
                          <p className="text-slate-600 mt-2">{laudo.analise.justificativa}</p>
                        </div>
                      )}
                    </div>
                  ))}
                </div>

                {/* Desktop Table */}
                <div className="hidden md:block overflow-x-auto">
                  <table className="w-full">
                    <thead className="bg-slate-50">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Arquivo</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Prioridade</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Gravidade</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Área</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Gradiente</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">TAVI</th>
                        <th className="px-4 py-3 text-left text-xs font-semibold text-slate-500 uppercase">Encaminhado</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {laudos.slice(0, 50).map((laudo) => (
                        <tr key={laudo.id} className={`hover:bg-slate-50 ${getPrioridadeBg(laudo.analise.prioridade)}`}>
                          <td className="px-4 py-3">
                            <div className="flex items-center gap-2">
                              {getFileIcon(laudo.formato)}
                              <span className="font-medium text-slate-800 truncate max-w-[200px]">{laudo.arquivo}</span>
                            </div>
                          </td>
                          <td className="px-4 py-3">
                            <span className={`px-2 py-1 rounded text-xs font-bold text-white ${getPrioridadeColor(laudo.analise.prioridade)}`}>
                              {laudo.analise.prioridade.toUpperCase()}
                            </span>
                          </td>
                          <td className="px-4 py-3 capitalize text-slate-700">{laudo.analise.gravidade}</td>
                          <td className="px-4 py-3 text-slate-700">{laudo.analise.area_valvar || '-'} cm²</td>
                          <td className="px-4 py-3 text-slate-700">{laudo.analise.gradiente_medio || '-'} mmHg</td>
                          <td className="px-4 py-3">
                            {laudo.analise.indicacao_tavi ? (
                              <span className="px-2 py-1 rounded text-xs font-bold bg-red-600 text-white">SIM</span>
                            ) : (
                              <span className="text-slate-400">-</span>
                            )}
                          </td>
                          <td className="px-4 py-3">
                            <button
                              onClick={() => toggleEncaminhado(laudo.id, !laudo.encaminhado)}
                              className={`p-2 rounded-lg transition-colors ${
                                laudo.encaminhado 
                                  ? 'bg-emerald-100 text-emerald-600' 
                                  : 'bg-slate-100 text-slate-400 hover:bg-emerald-50 hover:text-emerald-500'
                              }`}
                              title={laudo.encaminhado ? 'Encaminhado' : 'Marcar como encaminhado'}
                            >
                              {laudo.encaminhado ? <Check className="w-4 h-4" /> : <Send className="w-4 h-4" />}
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </div>
        )}

        {/* DASHBOARD VIEW */}
        {view === 'dashboard' && (
          <div className="space-y-6">
            {/* Period Filter */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
              <div className="flex flex-col sm:flex-row sm:items-center gap-4">
                <div className="flex items-center gap-2">
                  <Calendar className="w-5 h-5 text-slate-400" />
                  <span className="font-medium text-slate-700">Período:</span>
                </div>
                <div className="flex flex-wrap gap-2">
                  {(['dia', 'semana', 'mes', 'todos', 'custom'] as Periodo[]).map((p) => (
                    <button
                      key={p}
                      onClick={() => setPeriodo(p)}
                      className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                        periodo === p 
                          ? 'bg-blue-600 text-white' 
                          : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                      }`}
                    >
                      {p === 'dia' ? 'Hoje' : p === 'semana' ? 'Semana' : p === 'mes' ? 'Mês' : p === 'todos' ? 'Todos' : 'Personalizado'}
                    </button>
                  ))}
                </div>

                {periodo === 'custom' && (
                  <div className="flex items-center gap-2 flex-wrap">
                    <input
                      type="date"
                      value={customDateStart}
                      onChange={(e) => setCustomDateStart(e.target.value)}
                      className="px-3 py-1.5 border border-slate-300 rounded-lg text-sm"
                    />
                    <span className="text-slate-400">até</span>
                    <input
                      type="date"
                      value={customDateEnd}
                      onChange={(e) => setCustomDateEnd(e.target.value)}
                      className="px-3 py-1.5 border border-slate-300 rounded-lg text-sm"
                    />
                  </div>
                )}
              </div>
            </div>

            {/* Stats Cards */}
            {stats && (
              <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 sm:p-6">
                  <div className="flex items-center gap-3">
                    <div className="p-2 sm:p-3 bg-blue-100 rounded-xl">
                      <Activity className="w-5 h-5 sm:w-6 sm:h-6 text-blue-600" />
                    </div>
                    <div>
                      <p className="text-2xl sm:text-3xl font-bold text-slate-800">{stats.total_laudos}</p>
                      <p className="text-xs sm:text-sm text-slate-500">Total de Laudos</p>
                    </div>
                  </div>
                </div>

                <div className="bg-white rounded-xl shadow-sm border border-red-200 p-4 sm:p-6">
                  <div className="flex items-center gap-3">
                    <div className="p-2 sm:p-3 bg-red-100 rounded-xl">
                      <Heart className="w-5 h-5 sm:w-6 sm:h-6 text-red-600" />
                    </div>
                    <div>
                      <p className="text-2xl sm:text-3xl font-bold text-red-600">{stats.indicacao_tavi}</p>
                      <p className="text-xs sm:text-sm text-slate-500">Indicação TAVI</p>
                    </div>
                  </div>
                </div>

                <div className="bg-white rounded-xl shadow-sm border border-emerald-200 p-4 sm:p-6">
                  <div className="flex items-center gap-3">
                    <div className="p-2 sm:p-3 bg-emerald-100 rounded-xl">
                      <Send className="w-5 h-5 sm:w-6 sm:h-6 text-emerald-600" />
                    </div>
                    <div>
                      <p className="text-2xl sm:text-3xl font-bold text-emerald-600">{stats.encaminhados}</p>
                      <p className="text-xs sm:text-sm text-slate-500">Encaminhados</p>
                    </div>
                  </div>
                </div>

                <div className="bg-white rounded-xl shadow-sm border border-amber-200 p-4 sm:p-6">
                  <div className="flex items-center gap-3">
                    <div className="p-2 sm:p-3 bg-amber-100 rounded-xl">
                      <Clock className="w-5 h-5 sm:w-6 sm:h-6 text-amber-600" />
                    </div>
                    <div>
                      <p className="text-2xl sm:text-3xl font-bold text-amber-600">
                        {stats.total_laudos - stats.encaminhados}
                      </p>
                      <p className="text-xs sm:text-sm text-slate-500">Pendentes</p>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {/* Priority Breakdown */}
            {stats && (
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 sm:p-6">
                  <h3 className="font-bold text-slate-800 mb-4">Por Prioridade</h3>
                  <div className="space-y-4">
                    <div>
                      <div className="flex justify-between text-sm mb-1">
                        <span className="text-slate-600">Alta</span>
                        <span className="font-medium text-red-600">{stats.prioridade_alta}</span>
                      </div>
                      <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-red-500 rounded-full transition-all"
                          style={{ width: `${stats.total_laudos ? (stats.prioridade_alta / stats.total_laudos) * 100 : 0}%` }}
                        />
                      </div>
                    </div>
                    <div>
                      <div className="flex justify-between text-sm mb-1">
                        <span className="text-slate-600">Média</span>
                        <span className="font-medium text-amber-600">{stats.prioridade_media}</span>
                      </div>
                      <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-amber-500 rounded-full transition-all"
                          style={{ width: `${stats.total_laudos ? (stats.prioridade_media / stats.total_laudos) * 100 : 0}%` }}
                        />
                      </div>
                    </div>
                    <div>
                      <div className="flex justify-between text-sm mb-1">
                        <span className="text-slate-600">Baixa</span>
                        <span className="font-medium text-emerald-600">{stats.prioridade_baixa}</span>
                      </div>
                      <div className="h-3 bg-slate-100 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-emerald-500 rounded-full transition-all"
                          style={{ width: `${stats.total_laudos ? (stats.prioridade_baixa / stats.total_laudos) * 100 : 0}%` }}
                        />
                      </div>
                    </div>
                  </div>
                </div>

                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4 sm:p-6">
                  <h3 className="font-bold text-slate-800 mb-4">Por Gravidade</h3>
                  <div className="space-y-3">
                    {stats.por_gravidade && Object.entries(stats.por_gravidade).map(([gravidade, count]) => (
                      <div key={gravidade} className="flex items-center justify-between">
                        <span className="text-slate-600 capitalize">{gravidade}</span>
                        <span className="px-3 py-1 bg-slate-100 rounded-full text-sm font-medium text-slate-700">
                          {count}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {/* Recent Laudos */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
              <div className="p-4 sm:p-6 border-b border-slate-100">
                <h3 className="font-bold text-slate-800">Laudos Recentes</h3>
              </div>

              <div className="divide-y divide-slate-100">
                {laudos.slice(0, 10).map((laudo) => (
                  <div key={laudo.id} className="p-4 flex items-center justify-between gap-4 hover:bg-slate-50">
                    <div className="flex items-center gap-3 min-w-0">
                      <div className={`w-3 h-3 rounded-full ${getPrioridadeColor(laudo.analise.prioridade)}`} />
                      <div className="min-w-0">
                        <p className="font-medium text-slate-800 truncate">{laudo.arquivo}</p>
                        <p className="text-xs text-slate-500">
                          {new Date(laudo.timestamp).toLocaleString('pt-BR')}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2 flex-shrink-0">
                      {laudo.analise.indicacao_tavi && (
                        <span className="px-2 py-1 bg-red-100 text-red-600 text-xs font-medium rounded">TAVI</span>
                      )}
                      {laudo.encaminhado && (
                        <span className="px-2 py-1 bg-emerald-100 text-emerald-600 text-xs font-medium rounded">Encaminhado</span>
                      )}
                    </div>
                  </div>
                ))}

                {laudos.length === 0 && (
                  <div className="p-8 text-center text-slate-500">
                    Nenhum laudo encontrado para este período
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-4 mt-8">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 text-center text-sm text-slate-500">
          CardioScreen v2.0 • Powered by Claude Haiku
        </div>
      </footer>
    </div>
  );
}

export default App;
